import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import Header from './Header';

const API_ENDPOINTS = [
  {
    name: 'Save RFID Transaction Details',
    endpoint: 'SaveRFIDTransactionDetails',
    method: 'POST',
    description: 'Save new RFID transaction details to the inventory stock table.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: false,
    icon: 'fas fa-save text-white',
    highlight: 'primary',
    color: '#8E2DE2',
    sampleBody: {
      "ClientCode": "", // Will be filled dynamically
      "RFIDNumber": "RFID123456789",
      "ItemCode": "ITEM001",
      "CategoryId": 1,
      "ProductId": 2,
      "DesignId": 3,
      "PurityId": 4,
      "GrossWeight": "10.50",
      "NetWeight": "9.80",
      "BoxNumber": "BOX001",
      "Status": "ApiActive"
    }
  },
  {
    name: 'Update RFID Transaction Details',
    endpoint: 'UpdateRFIDTransactionDetails',
    method: 'POST',
    description: 'Update the status of the product to Active or Sold based on the RFID Number.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-edit text-white',
    highlight: 'info',
    color: '#4A00E0',
    sampleBody: {
      "ClientCode": "", // Will be filled dynamically
      "RFIDNumber": "RFID123456789",
      "Status": "Sold" // Can be "Sold" or "Active"
    }
  },
  {
    name: 'Get RFID Transaction Details',
    endpoint: 'GetRFIDTransactionDetails',
    method: 'POST',
    description: 'Retrieve all records from the inventory stock table.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-search text-white',
    highlight: 'primary',
    color: '#06beb6',
    sampleBody: {
      "ClientCode": "" // Will be filled dynamically
    }
  },
  {
    name: 'Delete Labelled Stock Items',
    endpoint: 'DeleteLabelledStockItems',
    method: 'POST',
    description: 'Delete one or more items using ClientCode, RFID Number, or ItemCode.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-trash text-white',
    highlight: 'danger',
    color: '#FF416C',
    sampleBody: {
      "ClientCode": "LS000183",
      "ItemCodes": ["ITEM001", "ITEM002"]
    }
  }
];

const Dashboard = () => {
  const [selectedApi, setSelectedApi] = useState(null);
  const [requestBody, setRequestBody] = useState('');
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [userInfo, setUserInfo] = useState(null);
  const [token, setToken] = useState('');
  const [dashboardError, setDashboardError] = useState('');
  const [showWelcomeModal, setShowWelcomeModal] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    console.log('Dashboard useEffect running');
    const storedToken = localStorage.getItem('token');
    const storedUserInfo = localStorage.getItem('userInfo');
    
    console.log('Stored token:', storedToken);
    console.log('Stored userInfo:', storedUserInfo);
    
    if (!storedToken) {
      console.log('No token found, redirecting to login');
      setDashboardError('No token found. Please login again.');
      navigate('/login');
      return;
    }

    // Validate token and extract client code
    try {
      console.log('Attempting to parse token');
      const tokenData = JSON.parse(atob(storedToken.split('.')[1]));
      console.log('Parsed token data:', tokenData);
      
      if (!tokenData.ClientCode) {
        console.log('No client code found in token');
        setDashboardError('Invalid token: No client code found.');
        throw new Error('Invalid token: No client code found');
      }
      setToken(storedToken);
      
      if (storedUserInfo) {
        console.log('Parsing stored user info');
        const parsedUserInfo = JSON.parse(storedUserInfo);
        if (parsedUserInfo.ClientCode !== tokenData.ClientCode) {
          console.log('Updating client code in user info');
          parsedUserInfo.ClientCode = tokenData.ClientCode;
          localStorage.setItem('userInfo', JSON.stringify(parsedUserInfo));
        }
        setUserInfo(parsedUserInfo);
      } else {
        console.log('Creating new user info');
        const userInfo = {
          Username: tokenData.sub,
          ClientCode: tokenData.ClientCode
        };
        localStorage.setItem('userInfo', JSON.stringify(userInfo));
        setUserInfo(userInfo);
      }
    } catch (err) {
      console.error('Token validation error:', err);
      setDashboardError('Token validation error: ' + err.message);
      localStorage.removeItem('token');
      localStorage.removeItem('userInfo');
      navigate('/login');
    }

    // Show welcome modal only once after login
    if (localStorage.getItem('showWelcomeToast') === 'true') {
      setShowWelcomeModal(true);
      localStorage.removeItem('showWelcomeToast');
      setTimeout(() => setShowWelcomeModal(false), 1000);
    }
  }, [navigate]);

  const handleApiSelect = (api) => {
    setSelectedApi(api);
    let sampleBodyCopy = JSON.parse(JSON.stringify(api.sampleBody));
    
    // Handle both array and object request bodies
    if (Array.isArray(sampleBodyCopy)) {
      sampleBodyCopy = sampleBodyCopy.map(item => ({
        ...item,
        ClientCode: userInfo?.ClientCode || ''
      }));
    } else {
      sampleBodyCopy = {
        ...sampleBodyCopy,
        ClientCode: userInfo?.ClientCode || ''
      };
    }
    
    setRequestBody(JSON.stringify(sampleBodyCopy, null, 2));
    setResponse('');
    setError('');
  };

  const isAuthenticated = !!token && !!userInfo?.ClientCode;

  const handleSendRequest = async () => {
    if (!selectedApi) return;
    if (!isAuthenticated) {
      setError('You must be logged in to test the API.');
      toast.error('You must be logged in to test the API.', {
        theme: 'colored',
        style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
      });
      return;
    }
    setLoading(true);
    setError('');
    setResponse('');
    try {
      const config = {
        headers: {
          'Content-Type': 'application/json'
        }
      };
      if (selectedApi.authRequired) {
        if (!token) {
          throw new Error('Authentication token is required for this endpoint');
        }
        config.headers['Authorization'] = `Bearer ${token}`;
      }
      const url = `${selectedApi.baseUrl}/${selectedApi.endpoint}`;
      let parsedBody;
      try {
        parsedBody = JSON.parse(requestBody);
      } catch (e) {
        throw new Error('Invalid JSON in request body');
      }

      // Special handling for GetRFIDTransactionDetails
      if (selectedApi.endpoint === 'GetRFIDTransactionDetails') {
        if (!parsedBody.ClientCode && !parsedBody.client_code) {
          throw new Error('ClientCode is required');
        }
        // Ensure payload uses 'client_code'
        parsedBody.client_code = parsedBody.ClientCode || parsedBody.client_code;
        delete parsedBody.ClientCode;
      }

      if (!parsedBody.client_code && !parsedBody.ClientCode) {
        throw new Error('ClientCode is required');
      }
      const result = await axios.post(url, parsedBody, config);
      if (result.data.Status === false) {
        throw new Error(result.data.Message || 'Operation failed');
      }
      setResponse(JSON.stringify(result.data, null, 2));
      toast.success(result.data.Message || 'API request successful!', {
        theme: 'colored',
        style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
      });
    } catch (err) {
      const errorMessage = err.response?.data?.Message || err.message || 'An error occurred while making the request.';
      setError(errorMessage);
      toast.error(errorMessage, {
        theme: 'colored',
        style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
      });
      if (err.response?.status === 401) {
        // Check for client code mismatch message (robust)
        const msg = (err.response?.data?.Message || err.response?.data || err.message || '').toLowerCase();
        if (msg.includes('clientcode')) {
          toast.error('You can only use your own ClientCode. Please use your assigned ClientCode only.', {
            theme: 'colored',
            style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
          });
          // Do NOT log out or navigate
          return;
        } else {
          toast.error('Authentication failed. Please login again.', {
            theme: 'colored',
            style: { fontFamily: 'Poppins, Montserrat, Arial, sans-serif' }
          });
          localStorage.removeItem('token');
          localStorage.removeItem('userInfo');
          navigate('/login');
        }
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(90deg, #f4f8ff 0%, #e9f0fb 100%)',
      fontFamily: 'Poppins, Montserrat, Arial, sans-serif',
      padding: 0
    }}>
      {/* Welcome Modal */}
      {showWelcomeModal && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: '100vw',
          height: '100vh',
          background: 'rgba(30,40,60,0.10)',
          zIndex: 9999,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          transition: 'opacity 0.2s',
        }}>
          <div style={{
            background: 'linear-gradient(135deg, #e3f0ff 0%, #fbeaec 100%)',
            borderRadius: 38,
            boxShadow: '0 18px 64px #0078d433, 0 2px 8px #d6000022',
            padding: '4rem 4rem 2.5rem 4rem',
            minWidth: 520,
            maxWidth: 720,
            minHeight: 320,
            textAlign: 'center',
            fontFamily: 'Poppins, Inter, sans-serif',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: 22,
            position: 'relative',
            border: '4px solid',
            borderImage: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%) 1',
            overflow: 'hidden',
          }}>
            {/* Confetti (simple SVG) */}
            <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: 70, pointerEvents: 'none', zIndex: 1 }}>
              <svg width="100%" height="70" viewBox="0 0 720 70">
                <g>
                  <rect x="20" y="18" width="14" height="14" fill="#0078d4"/>
                  <rect x="120" y="30" width="10" height="10" fill="#d60000"/>
                  <rect x="260" y="10" width="12" height="12" fill="#0078d4"/>
                  <rect x="400" y="28" width="14" height="14" fill="#d60000"/>
                  <rect x="540" y="16" width="12" height="12" fill="#0078d4"/>
                  <rect x="640" y="38" width="10" height="10" fill="#d60000"/>
                  <rect x="680" y="20" width="14" height="14" fill="#0078d4"/>
                </g>
              </svg>
            </div>
            {/* Party Icon */}
            <div style={{ fontSize: 70, marginBottom: 12, zIndex: 2 }}>
              <span role="img" aria-label="party">🎉</span>
            </div>
            <div style={{ fontWeight: 900, fontSize: 40, color: '#222', marginBottom: 12, zIndex: 2, letterSpacing: 0.3 }}>
              Welcome, {userInfo?.Username || 'User'}!
            </div>
            <div style={{ color: '#444', fontSize: 23, marginBottom: 0, zIndex: 2, fontWeight: 600, lineHeight: 1.4 }}>
              You have successfully logged in to <span style={{ color: '#0078d4', fontWeight: 800 }}>RFID <span style={{ color: '#d60000' }}>Secure API Dashboard</span></span>.
            </div>
          </div>
        </div>
      )}
      <Header userInfo={userInfo} />
      <ToastContainer />
      {dashboardError && (
        <div className="alert alert-danger m-4" style={{
          borderRadius: '12px',
          border: 'none',
          background: 'rgba(220, 53, 69, 0.1)',
          color: '#dc3545',
          boxShadow: '0 4px 10px rgba(0, 0, 0, 0.05)'
        }}>
          <i className="fas fa-exclamation-circle me-2"></i>
          {dashboardError}
        </div>
      )}
      <div style={{
        display: 'flex',
        flexDirection: 'row',
        justifyContent: 'center',
        alignItems: 'flex-start',
        maxWidth: 1600,
        margin: '0 auto',
        padding: '32px 0 0 0',
        minHeight: 'calc(100vh - 80px)'
      }}>
        {/* Sidebar */}
        <div style={{
          width: 320,
          minWidth: 260,
          maxWidth: 340,
          marginRight: 32,
          marginLeft: 24,
          alignSelf: 'flex-start',
          position: 'sticky',
          top: 32
        }}>
          <div className="card border-0 shadow-sm" style={{
            background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
            borderRadius: 18,
            boxShadow: '0 8px 24px rgba(0, 0, 0, 0.08)',
            marginBottom: 24
          }}>
            <div className="card-header border-0" style={{
              borderTopLeftRadius: 18,
              borderTopRightRadius: 18,
              background: 'rgba(255, 255, 255, 0.95)',
              padding: '1.1rem 1.3rem'
            }}>
              <h5 className="mb-0 d-flex align-items-center" style={{
                fontFamily: 'Poppins, Montserrat, Arial, sans-serif',
                fontWeight: 700,
                color: '#333',
                fontSize: 20
              }}>
                <i className="fas fa-list-alt me-2" style={{
                  background: 'linear-gradient(45deg, #667eea, #764ba2)',
                  WebkitBackgroundClip: 'text',
                  WebkitTextFillColor: 'transparent',
                  fontSize: '1.3rem'
                }}></i>
                API Endpoints
              </h5>
            </div>
            <div className="list-group list-group-flush p-2">
              {API_ENDPOINTS.map((api, index) => (
                <button
                  key={index}
                  className={`list-group-item list-group-item-action d-flex align-items-center ${selectedApi?.endpoint === api.endpoint ? 'active' : ''}`}
                  style={{
                    border: 'none',
                    background: selectedApi?.endpoint === api.endpoint ?
                      `linear-gradient(90deg, ${api.color} 0%, rgba(255,255,255,0.3) 100%)` :
                      'rgba(255, 255, 255, 0.5)',
                    color: selectedApi?.endpoint === api.endpoint ? '#fff' : '#333',
                    fontWeight: 500,
                    fontFamily: 'Poppins, Montserrat, Arial, sans-serif',
                    transition: 'all 0.3s ease',
                    marginBottom: 6,
                    borderRadius: 10,
                    padding: '10px 13px',
                    fontSize: 15
                  }}
                  onClick={() => handleApiSelect(api)}
                >
                  <div className="d-flex align-items-center w-100">
                    <div style={{
                      width: 28,
                      height: 28,
                      borderRadius: '50%',
                      background: selectedApi?.endpoint === api.endpoint ?
                        'rgba(255, 255, 255, 0.2)' :
                        `linear-gradient(135deg, ${api.color} 0%, rgba(255,255,255,0.8) 150%)`,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      marginRight: 10,
                      boxShadow: '0 2px 6px rgba(0, 0, 0, 0.08)'
                    }}>
                      <i className={`${api.icon}`} style={{
                        color: '#fff',
                        fontSize: '0.9rem'
                      }}></i>
                    </div>
                    <span>{api.name}</span>
                  </div>
                </button>
              ))}
            </div>
          </div>
          <div className="card border-0 shadow-sm" style={{
            background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
            borderRadius: 18,
            padding: '18px',
            boxShadow: '0 8px 24px rgba(0, 0, 0, 0.08)'
          }}>
            <div className="d-flex align-items-center mb-2">
              <div style={{
                width: 36,
                height: 36,
                borderRadius: '50%',
                background: 'linear-gradient(45deg, #4776E6, #8E54E9)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                marginRight: 12,
                boxShadow: '0 2px 6px rgba(0, 0, 0, 0.08)'
              }}>
                <i className="fas fa-info-circle text-white"></i>
              </div>
              <h5 className="mb-0" style={{ fontWeight: 600, color: '#333', fontSize: 17 }}>Learn More</h5>
            </div>
            <p className="text-muted mb-2" style={{ fontSize: '0.93rem' }}>
              Visit our RFID Integration page to learn how to integrate RFID in your third-party applications.
            </p>
            <a href="/rfid-integration" className="btn btn-sm w-100" style={{
              background: 'linear-gradient(45deg, #4776E6, #8E54E9)',
              color: 'white',
              border: 'none',
              borderRadius: 10,
              padding: '7px',
              fontWeight: 500,
              boxShadow: '0 2px 8px rgba(71, 118, 230, 0.13)',
              transition: 'all 0.3s',
              fontSize: 15
            }}>
              <i className="fas fa-plug me-2"></i>
              Integration Guide
            </a>
          </div>
        </div>
        {/* Main Card */}
        <div style={{ flex: 1, minWidth: 0, maxWidth: 900, alignSelf: 'flex-start' }}>
          {selectedApi ? (
            <div className="card border-0 shadow-sm" style={{
              borderRadius: 18,
              background: '#fff',
              minHeight: 420,
              marginBottom: 32
            }}>
              <div className="card-header border-0 d-flex align-items-center" style={{ 
                background: '#F9FAFB',
                padding: '1rem 1.5rem',
                borderTopLeftRadius: 16,
                borderTopRightRadius: 16
              }}>
                <div className="me-2 px-2 py-1" style={{
                  background: '#7C3AED',
                  color: '#fff',
                  borderRadius: '4px',
                  fontSize: '0.8rem',
                  fontWeight: 600
                }}>POST</div>
                <h5 className="mb-0" style={{ 
                  fontSize: '1.1rem',
                  fontWeight: 600,
                  color: '#111827'
                }}>{selectedApi.name}</h5>
              </div>
              
              <div className="card-body p-4">
                <div className="mb-4">
                  <h6 className="mb-2" style={{ 
                    color: '#111827',
                    fontSize: '0.9rem',
                    fontWeight: 600
                  }}>Description</h6>
                  <p style={{ 
                    color: '#6B7280',
                    fontSize: '0.9rem',
                    marginBottom: 0
                  }}>{selectedApi.description}</p>
                </div>
                
                <div className="mb-4">
                  <h6 className="mb-2" style={{ 
                    color: '#111827',
                    fontSize: '0.9rem',
                    fontWeight: 600
                  }}>Request Body</h6>
                  <div style={{ 
                    background: '#F9FAFB',
                    borderRadius: '8px',
                    padding: '1rem'
                  }}>
                    <textarea
                      className="form-control border-0"
                      value={requestBody}
                      onChange={(e) => setRequestBody(e.target.value)}
                      style={{ 
                        fontSize: '0.9rem',
                        background: 'transparent',
                        fontFamily: 'monospace',
                        resize: 'none',
                        height: 'auto',
                        minHeight: '200px'
                      }}
                    />
                  </div>
                </div>
                
                <button
                  className="btn w-100"
                  onClick={handleSendRequest}
                  disabled={loading || !isAuthenticated}
                  style={{
                    background: '#7C3AED',
                    color: '#fff',
                    padding: '0.75rem',
                    borderRadius: '8px',
                    fontSize: '0.9rem',
                    fontWeight: 600,
                    border: 'none',
                    transition: 'all 0.2s'
                  }}
                  onMouseOver={e => {
                    e.currentTarget.style.background = '#6D28D9';
                  }}
                  onMouseOut={e => {
                    e.currentTarget.style.background = '#7C3AED';
                  }}
                >
                  {loading ? (
                    <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                  ) : (
                    <>
                      <i className="fas fa-paper-plane me-2"></i>
                      Send Request
                    </>
                  )}
                </button>
                
                {error && (
                  <div className="alert alert-danger mt-4 mb-0" style={{ 
                    fontSize: '0.9rem',
                    borderRadius: '8px'
                  }}>
                    {error}
                  </div>
                )}
                
                {response && (
                  <div className="mt-4">
                    <h6 className="mb-2" style={{ 
                      color: '#111827',
                      fontSize: '0.9rem',
                      fontWeight: 600
                    }}>Response</h6>
                    <pre style={{ 
                      background: '#F9FAFB',
                      padding: '1rem',
                      borderRadius: '8px',
                      fontSize: '0.9rem',
                      margin: 0
                    }}>
                      <code>{response}</code>
                    </pre>
                  </div>
                )}
              </div>
            </div>
          ) : (
            <div className="card border-0 shadow-lg d-flex align-items-center justify-content-center w-100" style={{
              borderRadius: 18,
              background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
              minHeight: 320,
              height: '100%',
              boxShadow: '0 10px 28px rgba(0, 0, 0, 0.09)',
              marginBottom: 32
            }}>
              <div className="text-center p-4">
                <div style={{
                  width: 70,
                  height: 70,
                  borderRadius: '50%',
                  background: 'linear-gradient(45deg, #667eea 0%, #764ba2 100%)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  margin: '0 auto 16px',
                  boxShadow: '0 4px 12px rgba(102, 126, 234, 0.18)'
                }}>
                  <i className="fas fa-book fa-lg text-white"></i>
                </div>
                <h3 className="fw-bold mb-2" style={{
                  fontFamily: 'Poppins, Montserrat, Arial, sans-serif',
                  color: '#333',
                  fontSize: '1.4rem',
                  verticalAlign: 'middle'
                }}>
                  <img
                    src="/Logo/Sparkle RFID svg.svg"
                    alt="Sparkle RFID"
                    style={{
                      height: '28px',
                      marginRight: '8px',
                      verticalAlign: 'middle'
                    }}
                  />
                  RFID API
                </h3>
                <p className="mb-3" style={{
                  color: '#666',
                  fontSize: '1rem',
                  maxWidth: '400px',
                  margin: '0 auto'
                }}>
                  Select an API endpoint from the sidebar to view documentation and test the API.
                </p>
                <div className="d-flex flex-wrap justify-content-center gap-2 mt-2">
                  {API_ENDPOINTS.map((api, index) => (
                    <button
                      key={index}
                      className="btn btn-sm"
                      style={{
                        background: `linear-gradient(45deg, ${api.color} 0%, ${api.color}99 100%)`,
                        color: 'white',
                        border: 'none',
                        borderRadius: '8px',
                        padding: '5px 10px',
                        margin: '3px',
                        fontWeight: 500,
                        boxShadow: `0 2px 6px ${api.color}22`,
                        transition: 'all 0.3s',
                        fontSize: 14
                      }}
                      onClick={() => handleApiSelect(api)}
                      onMouseOver={e => {
                        e.currentTarget.style.transform = 'translateY(-1px)';
                        e.currentTarget.style.boxShadow = `0 4px 10px ${api.color}44`;
                      }}
                      onMouseOut={e => {
                        e.currentTarget.style.transform = 'translateY(0)';
                        e.currentTarget.style.boxShadow = `0 2px 6px ${api.color}22`;
                      }}
                    >
                      <i className={`${api.icon} me-1`}></i>
                      {api.name.length > 20 ? api.name.substring(0, 18) + '...' : api.name}
                    </button>
                  ))}
                </div>
               
              </div>
            </div>
          )}
        </div>
      </div>
      {/* Google Fonts for Poppins and Fira Mono */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600&family=Montserrat:wght@500&family=Fira+Mono&display=swap" rel="stylesheet" />
    </div>
  );
};

export default Dashboard;
